# Copyright (c) leaf\n# SPDX-License-Identifier: MIT\n\nimport os\n\nfrom launch import LaunchDescription\nfrom launch.actions import DeclareLaunchArgument\nfrom launch.substitutions import LaunchConfiguration, EnvironmentVariable\nfrom launch_ros.actions import Node\n\n\ndef generate_launch_description():\n    # ---- 声明参数 ----\n    agent_name_arg = DeclareLaunchArgument(\n        \"agent_name\", default_value=\"adam\",\n        description=\"Agent 命名空间前缀\"\n    )\n    repo_url_arg = DeclareLaunchArgument(\n        \"repo_url\", default_value=\"git@github.com:hachi-leaf/Adam-Soul.git\",\n        description=\"记忆仓库 SSH 地址\"\n    )\n    repo_dir_arg = DeclareLaunchArgument(\n        \"repo_dir\", default_value=os.path.expanduser(\"~/.adam/soul_repo\"),\n        description=\"记忆仓库本地路径\"\n    )\n    repo_fork_arg = DeclareLaunchArgument(\n        \"repo_fork\", default_value=\"main\",\n        description=\"远端分支名\"\n    )\n    openai_base_url_arg = DeclareLaunchArgument(\n        \"openai_base_url\", default_value=\"https://api.deepseek.com/v1\",\n        description=\"OpenAI 兼容 API 地址\"\n    )\n    openai_model_arg = DeclareLaunchArgument(\n        \"openai_model\", default_value=\"deepseek-v4-pro\",\n        description=\"模型名称\"\n    )\n    context_dir_arg = DeclareLaunchArgument(\n        \"context_dir\", default_value=os.path.expanduser(\"~/.adam/context\"),\n        description=\"上下文持久化目录\"\n    )\n    max_context_tokens_arg = DeclareLaunchArgument(\n        \"max_context_tokens\", default_value=\"200000\",\n        description=\"触发压缩的 token 阈值\"\n    )\n    loop_rate_arg = DeclareLaunchArgument(\n        \"loop_rate\", default_value=\"0.0\",\n        description=\"主循环频率 Hz，0=连续\"\n    )\n    mail_recipient_arg = DeclareLaunchArgument(\n        \"mail_recipient\", default_value=\"zxy_yys_leaf@163.com\",\n        description=\"邮件通知收件人\"\n    )\n\n    agent_name = LaunchConfiguration(\"agent_name\")\n    repo_url = LaunchConfiguration(\"repo_url\")\n    repo_dir = LaunchConfiguration(\"repo_dir\")\n    repo_fork = LaunchConfiguration(\"repo_fork\")\n    openai_base_url = LaunchConfiguration(\"openai_base_url\")\n    openai_model = LaunchConfiguration(\"openai_model\")\n    context_dir = LaunchConfiguration(\"context_dir\")\n    max_context_tokens = LaunchConfiguration(\"max_context_tokens\")\n    loop_rate = LaunchConfiguration(\"loop_rate\")\n    mail_recipient = LaunchConfiguration(\"mail_recipient\")\n\n    # ---- cs_input 节点 ----\n    input_mgmt_node = Node(\n        package=\"cs_input\", executable=\"input_mgmt_node\",\n        name=\"adam_input_mgmt\",\n        parameters=[{\"agent_name\": agent_name}],\n        output=\"screen\",\n    )\n    system_status_node = Node(\n        package=\"cs_input\", executable=\"system_status_node\",\n        name=\"system_status\",\n        parameters=[{\"agent_name\": agent_name}],\n        output=\"screen\",\n    )\n    user_command_node = Node(\n        package=\"cs_input\", executable=\"user_command_node\",\n        name=\"user_command\",\n        parameters=[{\"agent_name\": agent_name}],\n        output=\"screen\",\n    )\n\n    # ---- cs_output 节点 ----\n    output_mgmt_node = Node(\n        package=\"cs_output\", executable=\"output_mgmt_node\",\n        name=\"adam_output_mgmt\",\n        parameters=[{\"agent_name\": agent_name}],\n        output=\"screen\",\n    )\n    file_read_node = Node(\n        package=\"cs_output\", executable=\"file_read_node\",\n        name=\"file_read\",\n        parameters=[{\"agent_name\": agent_name}],\n        output=\"screen\",\n    )\n    file_write_node = Node(\n        package=\"cs_output\", executable=\"file_write_node\",\n        name=\"file_write\",\n        parameters=[{\"agent_name\": agent_name}],\n        output=\"screen\",\n    )\n    shell_exec_node = Node(\n        package=\"cs_output\", executable=\"shell_exec_node\",\n        name=\"shell_exec\",\n        parameters=[{\"agent_name\": agent_name}],\n        output=\"screen\",\n    )\n    user_notify_node = Node(\n        package=\"cs_output\", executable=\"user_notify_node\",\n        name=\"user_notify\",\n        parameters=[\n            {\"agent_name\": agent_name},\n            {\"mail_recipient\": mail_recipient},\n        ],\n        output=\"screen\",\n    )\n\n    # ---- cs_core 节点 ----\n    mrymt_node = Node(\n        package=\"cs_core\", executable=\"mrymt_node\",\n        name=\"mrymt_node\",\n        parameters=[\n            {\"agent_name\": agent_name},\n            {\"repo_url\": repo_url},\n            {\"repo_dir\": repo_dir},\n            {\"repo_fork\": repo_fork},\n            {\"openai_base_url\": openai_base_url},\n            {\"openai_api_key\": EnvironmentVariable(\"OPENAI_API_KEY\", default_value=\"\")},\n            {\"openai_model\": openai_model},\n        ],\n        output=\"screen\",\n    )\n    agent_loop_node = Node(\n        package=\"cs_core\", executable=\"agent_loop_node\",\n        name=\"agent_loop_node\",\n        arguments=[\"--log-level\", \"debug\"],\n        parameters=[\n            {\"agent_name\": agent_name},\n            {\"context_dir\": context_dir},\n            {\"max_context_tokens\": max_context_tokens},\n            {\"loop_rate\": loop_rate},\n            {\"openai_base_url\": openai_base_url},\n            {\"openai_api_key\": EnvironmentVariable(\"OPENAI_API_KEY\", default_value=\"\")},\n            {\"openai_model\": openai_model},\n        ],\n        output=\"screen\",\n    )\n\n    return LaunchDescription([\n        agent_name_arg,\n        repo_url_arg,\n        repo_dir_arg,\n        repo_fork_arg,\n        openai_base_url_arg,\n        openai_model_arg,\n        context_dir_arg,\n        max_context_tokens_arg,\n        loop_rate_arg,\n        mail_recipient_arg,\n        input_mgmt_node,\n        system_status_node,\n        user_command_node,\n        output_mgmt_node,\n        file_read_node,\n        file_write_node,\n        shell_exec_node,\n        user_notify_node,\n        mrymt_node,\n        agent_loop_node,\n    ])\n